1082: // maybeReap will remove the last internal traces of the named
1083: // priority level if it has no more use.  Call this after getting a
1084: // clue that the given priority level is undesired and idle.
1085: func (cfgCtlr *configController) maybeReap(plName string) {
1086: 	cfgCtlr.lock.RLock()
1087: 	defer cfgCtlr.lock.RUnlock()
1088: 	plState := cfgCtlr.priorityLevelStates[plName]
1089: 	if plState == nil {
1090: 		klog.V(7).Infof("plName=%s, plState==nil", plName)
1091: 		return
1092: 	}
1093: 	useless := plState.quiescing && plState.numPending == 0 && plState.queues.IsIdle()
1094: 	klog.V(7).Infof("plState.quiescing=%v, plState.numPending=%d, useless=%v", plState.quiescing, plState.numPending, useless)
1095: 	if !useless {
1096: 		return
1097: 	}
1098: 	klog.V(3).Infof("Triggered API priority and fairness config reloading because priority level %s is undesired and idle", plName)
1099: 	cfgCtlr.configQueue.Add(0)
1100: }
1101: 
1102: // maybeReapLocked requires the cfgCtlr's lock to already be held and
1103: // will remove the last internal traces of the named priority level if
1104: // it has no more use.  Call this if both (1) plState.queues is
1105: // non-nil and reported being idle, and (2) cfgCtlr's lock has not
1106: // been released since then.
1107: func (cfgCtlr *configController) maybeReapReadLocked(plName string, plState *priorityLevelState) {
1108: 	if !(plState.quiescing && plState.numPending == 0) {
1109: 		return
1110: 	}
1111: 	klog.V(3).Infof("Triggered API priority and fairness config reloading because priority level %s is undesired and idle", plName)
1112: 	cfgCtlr.configQueue.Add(0)
1113: }
